14	// A Reference interface represents a link reference in Markdown text.
15	type Reference interface {
16		// String implements Stringer.
17		String() string
18	
19		// Label returns a label of the reference.
20		Label() []byte
21	
22		// Destination returns a destination(URL) of the reference.
23		Destination() []byte
24	
25		// Title returns a title of the reference.
26		Title() []byte
27	}
28	
29	type reference struct {
30		label       []byte
31		destination []byte
32		title       []byte
33	}
34	
35	// NewReference returns a new Reference.
36	func NewReference(label, destination, title []byte) Reference {
37		return &reference{label, destination, title}
38	}
39	
40	func newASTReference(v *ast.LinkReferenceDefinition) Reference {
41		return &astReference{v}
42	}
43	
44	func (r *reference) Label() []byte {
45		return r.label
46	}
47	
48	func (r *reference) Destination() []byte {
49		return r.destination
50	}
51	
52	func (r *reference) Title() []byte {
53		return r.title
54	}
55	
56	func (r *reference) String() string {
57		return fmt.Sprintf("Reference{Label:%s, Destination:%s, Title:%s}", r.label, r.destination, r.title)
58	}
