40	var (
41		tocResultKey = parser.NewContextKey()
42		tocEnableKey = parser.NewContextKey()
43	)
44	
45	type tocTransformer struct {
46		r renderer.Renderer
47		p parser.Parser
48	}
49	
50	func (t *tocTransformer) Transform(n *ast.Document, reader text.Reader, pc parser.Context) {
51		if b, ok := pc.Get(tocEnableKey).(bool); !ok || !b {
52			return
53		}
54	
55		var (
56			toc         tableofcontents.Builder
57			tocHeading  = &tableofcontents.Heading{}
58			level       int
59			row         = -1
60			inHeading   bool
61			headingText bytes.Buffer
62		)
63	
64		if ids := pc.IDs().(stringValuesProvider).StringValues(); len(ids) > 0 {
65			toc.SetIdentifiers(ids)
66		}
67	
68		ast.Walk(n, func(n ast.Node, entering bool) (ast.WalkStatus, error) {
69			s := ast.WalkStatus(ast.WalkContinue)
70			if n.Kind() == ast.KindHeading {
71				if inHeading && !entering {
