	"github.com/microcosm-cc/bluemonday"
	strikethroughAst "github.com/yuin/goldmark/extension/ast"

	emojiAst "github.com/yuin/goldmark-emoji/ast"

	"github.com/gohugoio/hugo-goldmark-extensions/extras"
	passthroughAst "github.com/gohugoio/hugo-goldmark-extensions/passthrough"
	"github.com/gohugoio/hugo/markup/tableofcontents"

	"github.com/yuin/goldmark"
	"github.com/yuin/goldmark/ast"
	"github.com/yuin/goldmark/parser"
	"github.com/yuin/goldmark/renderer"
	"github.com/yuin/goldmark/text"
	"github.com/yuin/goldmark/util"
)

var (
	tocResultKey = parser.NewContextKey()
	tocEnableKey = parser.NewContextKey()
)

type tocTransformer struct {
	r renderer.Renderer
	p parser.Parser
}

func (t *tocTransformer) Transform(n *ast.Document, reader text.Reader, pc parser.Context) {
	if b, ok := pc.Get(tocEnableKey).(bool); !ok || !b {
		return
	}

	var (
		toc         tableofcontents.Builder
		tocHeading  = &tableofcontents.Heading{}
		level       int
		row         = -1
		inHeading   bool
		headingText bytes.Buffer
	)

	if ids := pc.IDs().(stringValuesProvider).StringValues(); len(ids) > 0 {
		toc.SetIdentifiers(ids)
	}

	ast.Walk(n, func(n ast.Node, entering bool) (ast.WalkStatus, error) {
		s := ast.WalkStatus(ast.WalkContinue)
		if n.Kind() == ast.KindHeading {
			if inHeading && !entering {
				tocHeading.Title = sanitizeTOCHeadingTitle(headingText.String())
				headingText.Reset()
				toc.AddAt(tocHeading, row, level-1)
				tocHeading = &tableofcontents.Heading{}
				inHeading = false
				return s, nil
			}

			inHeading = true
		}

		if !(inHeading && entering) {
			return s, nil
		}

		switch n.Kind() {
		case ast.KindHeading:
			heading := n.(*ast.Heading)
			level = heading.Level

			if level == 1 || row == -1 {
				row++
			}

			id, found := heading.AttributeString("id")
			if found {
				tocHeading.ID = string(id.([]byte))
				tocHeading.Level = level
			}
		case
			ast.KindCodeSpan,
			ast.KindLink,
			ast.KindImage,
			ast.KindEmphasis,
			strikethroughAst.KindStrikethrough,
			emojiAst.KindEmoji,
			extras.KindDelete,
			extras.KindInsert,
			extras.KindMark,
			extras.KindSubscript,
			extras.KindSuperscript:
			err := t.r.Render(&headingText, reader.Source(), n)
			if err != nil {
				return s, err
			}

			return ast.WalkSkipChildren, nil
		case
			ast.KindAutoLink,
			ast.KindRawHTML,
			ast.KindText,
			ast.KindString:
			err := t.r.Render(&headingText, reader.Source(), n)
			if err != nil {
				return s, err
			}
		case passthroughAst.KindPassthroughInline:
			headingText.Write(n.(*passthroughAst.PassthroughInline).Segment.Value(reader.Source()))
		}

		return s, nil
	})

	pc.Set(tocResultKey, toc.Build())
}

type tocMarkdown struct {
	r []renderer.Option
	p []parser.Option
}

func (m *tocMarkdown) Parser() parser.Parser {
	return tocParser{m}
}

func (m *tocMarkdown) SetParser(parser.Parser) {
}

func (m *tocMarkdown) Renderer() renderer.Renderer {
	return tocRenderer{m}
}

func (m *tocMarkdown) SetRenderer(renderer.Renderer) {
}

func (m *tocMarkdown) Convert(source []byte, writer io.Writer, opts ...parser.ParseOption) error {
	return nil
}

type tocParser struct {
	m *tocMarkdown
}

func (p tocParser) AddOptions(opts ...parser.Option) {
	p.m.p = append(p.m.p, opts...)
}

func (p tocParser) Parse(reader text.Reader, opts ...parser.ParseOption) ast.Node {
	return nil
}

type tocRenderer struct {
	m *tocMarkdown
}

func (r tocRenderer) AddOptions(opts ...renderer.Option) {
	r.m.r = append(r.m.r, opts...)
}

func (r tocRenderer) Render(w io.Writer, source []byte, n ast.Node) error {
	return nil
}

func tocMarkdownParserOptions(options []renderer.Option) []parser.Option {
	m := &tocMarkdown{r: slices.Clone(options)}
	passthroughAst.New(passthroughAst.Config{}).Extend(m)
	return m.p
}

func tocMarkdownRendererOptions(e goldmark.Extender, options []renderer.Option) []renderer.Option {
	m := &tocMarkdown{r: slices.Clone(options)}
	e.Extend(m)
	return m.r
}

type tocExtension struct {
	options []renderer.Option
}

func newTocExtension(options []renderer.Option) goldmark.Extender {
	return &tocExtension{
		options: options,
	}
}

func (e *tocExtension) Extend(m goldmark.Markdown) {
	r := goldmark.DefaultRenderer()
	r.AddOptions(e.options...)
	p := parser.NewParser()
	p.AddOptions(tocMarkdownParserOptions(e.options)...)
	m.Parser().AddOptions(parser.WithASTTransformers(util.Prioritized(&tocTransformer{
		r: r,
		p: p,
	},
		// This must run after the ID generation (priority 100).
		110)))
}

var tocSanitizerPolicy = newTOCSanitizerPolicy()

// newTOCSanitizerPolicy returns a bluemonday policy for sanitizing TOC heading
// titles against an allowlist of inline HTML elements and attributes,
// specifically excluding anchor elements to prevent links within TOC heading
