		if n.Kind() == ast.KindEmphasis {
			tag := "em"
			if n.(*ast.Emphasis).Level == 2 {
				tag = "strong"
			}
			headingText.WriteByte('<')
			headingText.WriteString(tag)
			headingText.WriteByte('>')
		}
	case
		ast.KindAutoLink,
		ast.KindRawHTML,
		ast.KindText,
		ast.KindString:
		err := t.r.Render(&headingText, reader.Source(), n)
		if err != nil {
			return s, err
		}
	case passthroughAst.KindPassthroughInline:
		if entering {
			headingText.Write(n.(*passthroughAst.PassthroughInline).Segment.Value(reader.Source()))
		}
		return ast.WalkSkipChildren, nil
	}

	return s, nil
})

